public class JdoPMFImpl extends AbstractOjbImpl implements JdoPMF , ThreadSafe { protected PersistenceManagerFactory factory ; public void dispose ( ) { super . dispose ( ) ; if ( this . getLogger ( ) . isDebugEnabled ( ) ) { this . getLogger ( ) . debug ( "OJB-JDO: Disposed OK!" ) ; } } public PersistenceManager getPersistenceManager ( ) { return factory . getPersistenceManager ( ) ; } public void initialize ( ) throws Exception { super . initialize ( ) ; try { factory = new OjbStorePMF ( ) ; if ( this . getLogger ( ) . isDebugEnabled ( ) ) { this . getLogger ( ) . debug ( "OJB-JDO: Started OK!" ) ; } } catch ( Throwable t ) { if ( this . getLogger ( ) . isFatalErrorEnabled ( ) ) { this . getLogger ( ) . fatalError ( "OJB-JDO: Started failed: Cannot create a Persistence Manager Factory." , t ) ; } } } }